<script setup lang="ts">
import { onMounted, ref } from 'vue'; import { api } from '../api/client'; import type { WorkerItem } from '../api/types'; import PageState from '../components/PageState.vue'; import StatusBadge from '../components/StatusBadge.vue'
const workers = ref<WorkerItem[]>([]); const health = ref<{ status: string; database: string; redis: string }>(); const loading = ref(true); const error = ref('')
async function load() { loading.value = true; try { const [healthResult, workerResult] = await Promise.all([api.health(), api.listWorkers()]); health.value = healthResult; workers.value = workerResult.items; error.value = '' } catch (reason) { error.value = reason instanceof Error ? reason.message : '读取 Worker 失败' } finally { loading.value = false } }
onMounted(load)
</script>
<template><section class="page"><header class="page-heading"><div><p class="eyebrow">SYSTEM</p><h1>系统运行</h1><p>数据库、Redis 与 Worker 的实时健康状态。</p></div></header><PageState :loading="loading" :error="error" @retry="load"><div class="health-line"><span>PostgreSQL <StatusBadge :status="health?.database === 'ok' ? 'ONLINE' : 'FAILED'" /></span><span>Redis <StatusBadge :status="health?.redis === 'ok' ? 'ONLINE' : 'FAILED'" /></span></div><div class="table-wrap"><table><thead><tr><th>Worker</th><th>状态</th><th>当前节点</th><th>主机 / PID</th><th>Heartbeat</th></tr></thead><tbody><tr v-for="worker in workers" :key="worker.id"><td><strong>{{ worker.id }}</strong></td><td><StatusBadge :status="worker.status" /></td><td><code>{{ worker.current_node_run_id ?? '—' }}</code></td><td>{{ worker.hostname }} / {{ worker.process_id }}</td><td>{{ new Date(worker.heartbeat_at).toLocaleString() }}</td></tr></tbody></table></div></PageState></section></template>
